// Function Node - Retorna apenas o payload para POST /2/tweets
// Texto vem SEMPRE do node: "When Executed by Another Workflow"

// Texto do post
const text =
  $('Switch').first().json.body.post.legenda_x
    ? String($('Switch').first().json.body.post.legenda_x).trim()
    : '';

// Mídias (vindas do input atual)
const data = $input.all()[0]?.json ?? {};

let mediaIds = [];

if (Array.isArray(data.media_ids)) {
  mediaIds = data.media_ids;
}

if (data.media_id || data.media_id_string) {
  mediaIds.push(data.media_id_string ?? data.media_id);
}

// Normaliza + remove duplicados + limite do X
mediaIds = [...new Set(
  mediaIds.map(v => v == null ? '' : String(v).trim()).filter(Boolean)
)].slice(0, 4);

// Payload final (somente retorno)
return [
  {
    json: mediaIds.length > 0
      ? {
          text,
          media: {
            media_ids: mediaIds,
          },
        }
      : {
          text,
        },
  },
];

